export function IcoGeocode() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Text lines (left) */}
      <rect x="18" y="36" width="60" height="9" rx="3" fill={palette.mid} opacity="0.6" />
      <rect x="18" y="52" width="50" height="9" rx="3" fill={palette.mid} opacity="0.45" />
      <rect x="18" y="68" width="55" height="9" rx="3" fill={palette.mid} opacity="0.30" />
      {/* Arrow */}
      <line x1="95" y1="65" x2="120" y2="65" stroke={palette.accent} strokeWidth="3.5" strokeLinecap="round" />
      <polygon points="120,60 130,65 120,70" fill={palette.accent} />
      {/* Pin (right) */}
      <circle cx="155" cy="55" r="14" fill={palette.accent} />
      <circle cx="155" cy="55" r="6" fill={palette.dark} />
      <polygon points="155,69 147,55 163,55" fill={palette.accent} />
    </svg>
  );
}
